BEGIN;

-- croup: croup-icu
UPDATE decision_nodes SET body = E'**ICU admission criteria:**\n• Impending or actual respiratory failure\n• Requiring intubation\n• Severe croup unresponsive to maximal medical therapy\n\n**Intubation pearls:**\n• Use ETT **0.5-1.0 size smaller** than age-predicted\n• Oral intubation preferred\n• Have multiple smaller tube sizes available\n• ENT/anesthesia at bedside for surgical airway backup\n\n**Post-intubation:**\n• Continue [Dexamethasone](#/drug/dexamethasone/pediatric croup) 0.6 mg/kg q6-12h (consider for extubation facilitation)\n• Sedation to prevent self-extubation\n• Plan extubation with leak test after 24-72 hours\n\n**<3% of hospitalized croup patients require intubation** — this is rare.', recommendation = E'ICU admission with continuous monitoring. ETT 0.5-1.0 size smaller than predicted. Continue dexamethasone. Plan extubation with leak test after 24-72 hours of improvement. Consult ENT if atypical course or concern for structural airway pathology.' WHERE id = 'croup-icu' AND tree_id = 'croup';

-- thyroid: thyroid-hypo-icu
UPDATE decision_nodes SET body = E'**Continue:**\n• IV [Levothyroxine](#/drug/levothyroxine/decompensated hypothyroidism) maintenance (50-100 mcg/day or 1.2 mcg/kg/day)\n• Stress-dose hydrocortisone until cortisol results available\n• IV liothyronine if started (reassess at 48h)\n• Aggressive treatment of precipitant (antibiotics if infection suspected)\n• Passive rewarming\n• Glucose + electrolyte monitoring\n\n**Consults:**\n• Endocrinology\n• Consider ENT/anesthesia if airway concerns\n\n**Complications to watch for:**\n• Arrhythmias during hormone replacement (especially if T3 used)\n• Pericardial tamponade (rare — effusion usually improves with treatment; avoid pericardiocentesis if possible due to bleeding risk from acquired vWD) [3]\n• Seizures (potentially exacerbated by hyponatremia)\n• Ileus → megacolon → perforation', recommendation = E'ICU admission. Endocrinology consult. Continue IV T4 + steroids.' WHERE id = 'thyroid-hypo-icu' AND tree_id = 'thyroid';

-- angioedema: angio-pregnancy
UPDATE decision_nodes SET body = E'Physiologic changes in pregnancy can **mitigate, aggravate, or have no effect** on underlying HAE — variable and unpredictable. [5]\n\n**Preferred acute treatment:**\n• [Berinert](#/drug/berinert/hereditary angioedema) 20 units/kg IV — plasma-derived C1-INH, considered safest option [5]\n\n**If Berinert unavailable:**\n• [Ruconest](#/drug/ruconest/hereditary angioedema) (recombinant C1-INH) — recommended if plasma-derived C1-INH not available and no rabbit allergy [5]\n• [Icatibant](#/drug/icatibant/hereditary angioedema) — for life-threatening attacks only when C1-INH unavailable. Recent small studies suggest safety in pregnancy. [5]\n\n**Estrogens can exacerbate bradykinin signaling** — estrogen-containing products may worsen HAE.', recommendation = E'[Berinert](#/drug/berinert/hae pregnancy) 20 units/kg IV is preferred in pregnancy. [Ruconest](#/drug/ruconest/hereditary angioedema) or [Icatibant](#/drug/icatibant/hereditary angioedema) only if C1-INH unavailable.' WHERE id = 'angio-pregnancy' AND tree_id = 'angioedema';

-- distal-radius: dr-proc-sed
UPDATE decision_nodes SET body = E'**Procedural sedation** provides excellent analgesia and amnesia but requires more resources and time.\n\n**COMMON AGENTS:**\n• [Ketamine](#/drug/ketamine/procedural sedation) 1–2 mg/kg IV — dissociative, maintains airway reflexes\n• [Propofol](#/drug/propofol/procedural sedation) 0.5–1 mg/kg IV — rapid onset/offset, no analgesia (add fentanyl)\n• **Etomidate** 0.1–0.15 mg/kg IV — hemodynamically stable\n\n**REQUIREMENTS:**\n• NPO assessment (ideally 2+ hours for clear liquids)\n• Dedicated monitoring nurse\n• Capnography, pulse oximetry, cardiac monitor\n• Resuscitation equipment at bedside\n• Longer ED stay (mean 4.6 hours vs 1.5 hours for hematoma block) [4]\n\n**BEST FOR:** Complex reductions, highly anxious patients, pediatric patients who cannot cooperate with hematoma block.' WHERE id = 'dr-proc-sed' AND tree_id = 'distal-radius';

-- chest-tube: ctube-anesthesia
UPDATE decision_nodes SET body = E'LOCAL ANESTHESIA — FIELD BLOCK\nInadequate anesthesia is the most common reason for procedural difficulty.\n\nTECHNIQUE\n1. Skin wheal: 22-gauge needle, raise a wheal at the incision site with 2% lidocaine with epinephrine\n2. Subcutaneous tissue: infiltrate generously along the planned dissection tract\n3. Intercostal muscles: fan lidocaine through the muscle layers\n4. Periosteum: anesthetize the rib periosteum above AND below — this is extremely painful if missed\n5. Parietal pleura: advance needle over the superior rib edge while aspirating. When air is aspirated (confirming pleural space), inject 5-10 mL along the parietal pleura — this is the most sensitive layer\n\nTotal: up to 30 mL of 2% [Lidocaine](#/drug/lidocaine/chest tube) with epinephrine (max 7 mg/kg with epi).\n\nPROCEDURAL SEDATION\nConsider sedation (ketamine, propofol, etomidate) for awake patients if clinical situation allows.' WHERE id = 'ctube-anesthesia' AND tree_id = 'chest-tube';

-- ich: ich-coag-adj
UPDATE decision_nodes SET body = E'**Not on anticoagulation — consider adjunct measures:**\n\n**Tranexamic acid (TXA):**\n• [TXA](#/drug/tranexamic-acid/ich hemostasis) 1 g IV over 10 min (within 3h of onset)\n• Significant reduction in hematoma expansion (OR 0.82)\n• Did NOT improve mortality or functional outcomes in TICH-2\n• May be considered — TICH-3 trial underway\n\n**Antiplatelet agents:**\n• Platelet transfusion is **NOT recommended** (PATCH trial — worse outcomes)\n• [Desmopressin (DDAVP)](#/drug/desmopressin/ich hemostasis) 0.3 mcg/kg IV may be considered (limited evidence, DASH pilot)\n\n**Thrombocytopenia:**\n• Target platelets >100,000 if possible\n• Transfuse platelets if count <100,000\n\n**Coagulation factors:**\n• Check fibrinogen — supplement with cryoprecipitate if <200 mg/dL\n• Correct any identified coagulopathy' WHERE id = 'ich-coag-adj' AND tree_id = 'ich';

-- aub: aub-coagulopathy
UPDATE decision_nodes SET body = E'Up to **20% of women** with heavy menstrual bleeding have an underlying bleeding disorder. **von Willebrand disease** is most common (up to 13%).\n\n**Testing:**\n• vWF antigen, ristocetin cofactor activity, Factor VIII\n• Consult hematology for interpretation\n\n**Treatment of AUB with coagulopathy:**\n• [Tranexamic Acid](#/drug/tranexamic-acid/aub) — first-line adjunct, reduces bleeding 30-55%\n• [Desmopressin (DDAVP)](#/drug/desmopressin/vwd aub) 0.3 mcg/kg IV — for known vWD responders. Use with caution: risk of fluid retention and hyponatremia. Do NOT give with massive hemorrhage + IV fluid resuscitation.\n• Recombinant factor VIII and vWF concentrate for severe vWD\n• Hormonal therapy (OCPs, progestins) also effective\n• **Avoid NSAIDs** — impair platelet aggregation\n\n**Hematology consult** recommended for all confirmed coagulopathies.' WHERE id = 'aub-coagulopathy' AND tree_id = 'aub';

BEGIN;

-- thyroid: thyroid-hypo-icu
UPDATE decision_nodes SET body = E'**Continue:**\n• IV [Levothyroxine](#/drug/levothyroxine/decompensated hypothyroidism) maintenance (50-100 mcg/day or 1.2 mcg/kg/day)\n• Stress-dose hydrocortisone until cortisol results available\n• IV liothyronine if started (reassess at 48h)\n• Aggressive treatment of precipitant (antibiotics if infection suspected)\n• Passive rewarming\n• Glucose + electrolyte monitoring\n\n**Consults:**\n• Endocrinology\n• Consider ENT/anesthesia if airway concerns\n\n**Complications to watch for:**\n• Arrhythmias during hormone replacement (especially if T3 used)\n• Pericardial tamponade (rare — effusion usually improves with treatment; avoid pericardiocentesis if possible due to bleeding risk from acquired vWD) [3]\n• Seizures (potentially exacerbated by hyponatremia)\n• Ileus → megacolon → perforation', recommendation = E'ICU admission. Endocrinology consult. Continue IV T4 + steroids.' WHERE id = 'thyroid-hypo-icu' AND tree_id = 'thyroid';

-- thyroid: thyroid-hypo-floor
UPDATE decision_nodes SET body = E'**Transition plan:**\n• Switch to PO [Levothyroxine](#/drug/levothyroxine/hypothyroid maintenance) (1.6 mcg/kg/day) when tolerating oral intake\n• Taper hydrocortisone over 2-3 days once cortisol results confirm adequate adrenal function\n• Aggressive bowel regimen (hypothyroid patients have severe constipation)\n• Telemetry monitoring for arrhythmias\n\n**Follow-up:**\n• TSH recheck in 6-8 weeks (adjustments in 12.5-25 mcg increments)\n• Endocrinology referral for dose titration\n• Patient education: lifelong therapy, medication adherence, sick-day rules, MedicAlert bracelet\n• Identify and address precipitant (medication noncompliance? new drug interaction?)', recommendation = E'Monitored floor with telemetry. Transition to PO T4. Endocrinology follow-up.' WHERE id = 'thyroid-hypo-floor' AND tree_id = 'thyroid';

-- angioedema: angio-pregnancy
UPDATE decision_nodes SET body = E'Physiologic changes in pregnancy can **mitigate, aggravate, or have no effect** on underlying HAE — variable and unpredictable. [5]\n\n**Preferred acute treatment:**\n• [Berinert](#/drug/berinert/hereditary angioedema) 20 units/kg IV — plasma-derived C1-INH, considered safest option [5]\n\n**If Berinert unavailable:**\n• [Ruconest](#/drug/ruconest/hereditary angioedema) (recombinant C1-INH) — recommended if plasma-derived C1-INH not available and no rabbit allergy [5]\n• [Icatibant](#/drug/icatibant/hereditary angioedema) — for life-threatening attacks only when C1-INH unavailable. Recent small studies suggest safety in pregnancy. [5]\n\n**Estrogens can exacerbate bradykinin signaling** — estrogen-containing products may worsen HAE.', recommendation = E'[Berinert](#/drug/berinert/hae pregnancy) 20 units/kg IV is preferred in pregnancy. [Ruconest](#/drug/ruconest/hereditary angioedema) or [Icatibant](#/drug/icatibant/hereditary angioedema) only if C1-INH unavailable.' WHERE id = 'angio-pregnancy' AND tree_id = 'angioedema';

